struct FileObject { 
    path: String,
    content_hash: u64,
}
impl std::fmt::Display for FileObject {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(f, "File at {} (Hash: {})", self.path, self.content_hash)
    }
}

fn process_files(files: Vec<FileObject>) -> usize {
    let mut count = 0;
    for file in files.into_iter() {
        println!("Processing object: {}", file);
        count += 1;
    }
    count
}

fn main() {
    let site_data = vec![ 
        FileObject { path: "index.html".to_string(), content_hash: 12345 },
        FileObject { path: "about.md".to_string(), content_hash: 67890 },
        FileObject { path: "contact.json".to_string(), content_hash: 99999 } 
    ];
    let total = process_files(site_data);
    println!("Successfully processed {} files.", total);
}

use std::collections::HashMap;

struct UserRecord {
    id: u32,
    role: String,
    is_active: bool,
}

fn process_user_list(users: Vec<UserRecord>, callback: impl Fn(&UserRecord) -> Result<(), &'static str>) -> Result<(), &'static str> {
    let mut count = 0;
    for user in users.into_iter() {
        if !user.is_active {
            return Err("Cannot process inactive user record.");
        }

        callback(&user)?;
        count += 1;
    }

    if count == 0 {
        return Ok(())
    }

    Ok(())
}

fn main() {
    let users = vec![ 
        UserRecord { id: 1, role: "admin".to_string(), is_active: true },
        UserRecord { id: 2, role: "editor".to_string(), is_active: true },
        UserRecord { id: 3, role: "viewer".to_string(), is_active: false },
    ];

    let callback = |user: &UserRecord| -> Result<(), &'static str> {
        println!("Processing user ID: {}", user.id);
        Ok(()) 
    };

    match process_user_list(users, callback) {
        Ok(_) => println!("Successfully processed all records."),
        Err(e) => eprintln!("Error during processing: {}", e),
    }
}
